// === Two LEDs + Pushbutton ===
// D12 → LED1 (Red)  via 220Ω
// D13 → LED2 (Green) via 220Ω
// D2  ← Button with 10kΩ pull-down to GND

const int LED1_PIN   = 12;
const int LED2_PIN   = 13;
const int BUTTON_PIN =  2;

void setup() {
  pinMode(LED1_PIN,   OUTPUT);
  pinMode(LED2_PIN,   OUTPUT);
  pinMode(BUTTON_PIN, INPUT);   // pull-down resistor on board
  Serial.begin(9600);
  Serial.println("Circuit ready. Press button to toggle LEDs.");
}

void loop() {
  int btnState = digitalRead(BUTTON_PIN);

  if (btnState == HIGH) {
    // Button pressed: both LEDs ON
    digitalWrite(LED1_PIN, HIGH);
    digitalWrite(LED2_PIN, HIGH);
    Serial.println("Button pressed  → LEDs ON");
  } else {
    // Button released: LEDs alternate blink
    digitalWrite(LED1_PIN, HIGH);
    digitalWrite(LED2_PIN, LOW);
    delay(400);
    digitalWrite(LED1_PIN, LOW);
    digitalWrite(LED2_PIN, HIGH);
    delay(400);
  }
}

